  "inlineSchema": "// Schema Prisma — Sistema de Duplas Missionárias — Associação Paulistana\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// Perfis de acesso do sistema\nenum Perfil {\n  ADMINISTRADOR\n  COORDENADOR_REGIONAL\n  PASTOR_DISTRITAL\n  LIDER_REGIOES\n}\n\n// Status da dupla missionária\nenum StatusDupla {\n  ATIVA\n  PENDENTE\n  INATIVA\n}\n\n// Tipo do segundo membro da dupla\nenum TipoMembro2 {\n  MEMBRO_IASD\n}\n\n// Tipo de projeto missionário\nenum TipoProjeto {\n  CASA_A_CASA\n  PEQUENOS_GRUPOS\n  ACAO_SOCIAL\n  EVANGELISMO_PUBLICO\n}\n\n// Usuários do sistema\nmodel Usuario {\n  id       Int      @id @default(autoincrement())\n  nome     String\n  email    String   @unique\n  senha    String\n  perfil   Perfil\n  ativo    Boolean  @default(true)\n  criadoEm DateTime @default(now())\n\n  // Relacionamentos opcionais por perfil\n  regiaoId   Int?\n  distritoId Int?\n  regiao     Regiao?   @relation(fields: [regiaoId], references: [id])\n  distrito   Distrito? @relation(fields: [distritoId], references: [id])\n}\n\n// Regiões da Associação Paulistana\nmodel Regiao {\n  id        Int      @id @default(autoincrement())\n  nome      String   @unique\n  descricao String?\n  cor       String   @default(\"#1A3A6B\") // cor identificadora do card\n  criadoEm  DateTime @default(now())\n\n  distritos Distrito[]\n  usuarios  Usuario[]\n}\n\n// Distritos dentro de cada região\nmodel Distrito {\n  id       Int      @id @default(autoincrement())\n  nome     String\n  regiaoId Int\n  membros  Int      @default(0)\n  criadoEm DateTime @default(now())\n\n  regiao   Regiao    @relation(fields: [regiaoId], references: [id])\n  duplas   Dupla[]\n  usuarios Usuario[]\n  igrejas  Igreja[]\n}\n\n// Igrejas/congregações do distrito\nmodel Igreja {\n  id         Int      @id @default(autoincrement())\n  nome       String\n  distritoId Int\n  membros    Int      @default(0)\n  criadoEm   DateTime @default(now())\n\n  distrito Distrito @relation(fields: [distritoId], references: [id])\n  duplas   Dupla[]\n}\n\n// Duplas Missionárias\nmodel Dupla {\n  id Int @id @default(autoincrement())\n\n  // Localização\n  regiaoNome String\n  distritoId Int\n  igrejaId   Int?\n  bairro     String\n\n  // Fotos (armazenadas como base64 no Firebase Storage)\n  fotoLider   String?\n  fotoMembro2 String?\n\n  // Tipo de projeto\n  tipoProjeto TipoProjeto\n\n  // Membro 1 (líder)\n  liderNome     String\n  liderTelefone String?\n  liderEmail    String?\n  liderIgreja   String?\n\n  // Membro 2\n  membro2Tipo     TipoMembro2\n  membro2Nome     String\n  membro2Telefone String?\n  membro2Email    String?\n\n  // Acompanhamento\n  estudoBiblico       String?\n  statusEstudoBiblico String?\n  statusEvangelismo   String?\n  batismos            Int     @default(0)\n\n  // Metadados\n  status            StatusDupla @default(ATIVA)\n  pessoasAlcancadas Int         @default(0)\n  observacoes       String?\n  dataInicio        DateTime    @default(now())\n  criadoEm          DateTime    @default(now())\n  atualizadoEm      DateTime    @updatedAt\n\n  // Relacionamentos\n  distrito        Distrito        @relation(fields: [distritoId], references: [id])\n  igreja          Igreja?         @relation(fields: [igrejaId], references: [id])\n  estudosBiblicos EstudoBiblico[]\n  evangelismos    Evangelismo[]\n}\n\n// Estudos Bíblicos cadastrados para acompanhamento\nmodel EstudoBiblico {\n  id            Int      @id @default(autoincrement())\n  nomeEstudante String\n  endereco      String\n  cidade        String\n  estado        String\n  whatsapp      String\n  diaEstudo     String\n  duplaId       Int\n  serie         String\n  licaoAtual    Int\n  criadoEm      DateTime @default(now())\n  atualizadoEm  DateTime @updatedAt\n\n  dupla Dupla @relation(fields: [duplaId], references: [id])\n}\n\n// Cadastros de evangelismo\nmodel Evangelismo {\n  id             Int      @id @default(autoincrement())\n  nomePessoa     String\n  endereco       String\n  cidade         String\n  estado         String\n  whatsapp       String\n  diaEvangelismo String\n  duplaId        Int\n  serie          String\n  estudoAtual    Int\n  criadoEm       DateTime @default(now())\n  atualizadoEm   DateTime @updatedAt\n\n  dupla Dupla @relation(fields: [duplaId], references: [id])\n}\n",
